#include <stdio.h>
#include <stdbool.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    // weekend days pre‑computed
    bool isWeekend[31] = {false};
    int weekendDays[] = {6,7,13,14,20,21,27,28};
    for (int i = 0; i < 8; ++i) isWeekend[ weekendDays[i] ] = true;
    while (T--) {
        int N; scanf("%d", &N);
        bool isFestival[31] = {false};
        int overlap = 0;
        for (int i = 0; i < N; ++i) {
            int d; scanf("%d", &d);
            isFestival[d] = true;
            if (isWeekend[d]) ++overlap;
        }
        int total = 8 + N - overlap;
        printf("%d\n", total);
    }
    return 0;
}

