#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    weekend = {6,7,13,14,20,21,27,28}
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        overlap = 0
        for _ in range(N):
            d = int(next(it))
            if d in weekend:
                overlap += 1
        total = 8 + N - overlap
        out_lines.append(str(total))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

